import { Component } from '@angular/core';
import { RegistrosService } from '../services/registrosService';
import { Register } from '../interfaces/register';
import Swal from 'sweetalert2';
import { Router } from '@angular/router';


@Component({
  selector: 'app-new-record',
  templateUrl: './new-record.component.html',
  styleUrls: ['./new-record.component.css'],
})
export class NewRecordComponent {
  concepto: string = '';
  observaciones: string = '';
  categoria: string = '';
  cantidad: number = 0;
  tipoOpciones = ['gasto', 'ingreso'];
  tipo: string = '';

  constructor(
    private registrosService: RegistrosService,
    private router: Router
  ) {}

  async btnCrear() {
    console.log('Btn crear');
    console.log(this.concepto, this.observaciones, this.categoria, this.cantidad, this.tipo);

    if (this.isValidInput()) {
      //Inputs validos
      try {
        let registro: Register;
        registro = {
          id: '0',
          concepto: this.concepto.trim().toLowerCase(),
          observaciones: this.observaciones.trim().toLowerCase(),
          categoria: this.categoria.trim().toLowerCase(),
          cantidad: this.cantidad,
          tipo: this.tipo,
          created_at: new Date
        };
        //Crear registro
        let response = this.registrosService.newRegistro(registro);
        if(await response) {
          Swal.fire({
            icon: 'success',
            title: 'Creado correctamente'
          }).then((result) => {
            this.router.navigate(['/registros']);
          })
        }
      } catch (error) {
        console.log(error);
      }
    } else {
      //Inputs invalidos
      Swal.fire({
        icon: 'error',
        title: 'Oops...',
        text: 'Valores no validos'    
      })
    }
  }

  isValidInput(): boolean {
    return this.concepto != '' && 
    this.observaciones != ''  && 
    this.categoria != ''  && 
    this.tipoOpciones.includes(this.tipo) &&
    typeof this.cantidad === 'number' &&
    this.cantidad > 0
  }
}
<h1>Nuevo registro</h1>

<div id="form-nuevo-registro">
    <div>
      <label for="registro-concepto">Concepto</label>
      <input type="text" id="registro-concepto" name="concepto" [(ngModel)]="concepto" required />
    </div>

    <div>
      <label for="registro-observaciones">Observaciones</label>
      <textarea id="registro-observaciones" rows="4" cols="50" name="observaciones" [(ngModel)]="observaciones" required></textarea>
    </div>


    <datalist id="datalist-categorias">
      <option value="Nomina"></option>
      <option value="Deporte"></option>
      <option value="Restaurante"></option>
      <option value="Supermercado"></option>
      <option value="Estudios"></option>
      <option value="Seguros"></option>
      <option value="Hogar"></option>
      <option value="Otro"></option>
    </datalist>

    <div>
      <label for="registro-categoria">Categoria</label>
      <input list="datalist-categorias" id="registro-categoria" name="categoria" [(ngModel)]="categoria" required />
    </div>

    <label for="registro-cantidad">Cantidad (€)</label>
    <input type="number" id="registro-cantidad" name="cantidad" min="0" max="1000042" [(ngModel)]="cantidad" required/>

    <fieldset>
      <legend>Tipo</legend>

        <input type="radio" id="rb-gasto" name="tipo" value="gasto" [(ngModel)]="tipo" /> 
        <label for="rb-gasto">Gasto</label>

        <input type="radio" id="rb-ingreso" name="tipo" value="ingreso" [(ngModel)]="tipo" /> 
        <label for="rb-ingreso">Ingreso</label>

    </fieldset>

    <button id="form-crear" type="submit" (click)="btnCrear()">Crear</button>
</div>
